import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type PropsWithChildren,
} from "react";
import {
  fetchAdminAccountInfo,
  hasCompleteStoredAdminApiKey,
  readStoredAdminApiKey,
  signedAdminRequest,
} from "@/utils/adminKeyAuth";
import { walletGetItem, walletSetItem } from "@/utils/storage";

export interface BrokerInfoContextState {
  brokerId?: string;
  brokerName?: string;
  brokerTier?: string;
  baseMakerFeeRate?: number;
  baseTakerFeeRate?: number;
  baseRwaMakerFeeRate?: number;
  baseRwaTakerFeeRate?: number;
  updateBrokerInfo: () => void;
  isLoading: boolean;
}

export const BrokerInfoContext = createContext<BrokerInfoContextState | null>(
  null
);

type StoredBrokerProfile = {
  brokerId?: string;
  brokerName?: string;
  name?: string;
  builderName?: string;
  role?: string;
  brokerTier?: string;
  baseMakerFeeRate?: number;
  baseTakerFeeRate?: number;
  baseRwaMakerFeeRate?: number;
  baseRwaTakerFeeRate?: number;
};

type BrokerNamePayload = {
  data?: { rows?: Array<{ broker_id?: string; broker_name?: string }> };
  rows?: Array<{ broker_id?: string; broker_name?: string }>;
};

type BrokerTierPayload = {
  data?: BrokerTierFields;
} & BrokerTierFields;

type BrokerTierFields = {
  type?: string;
  base_maker_fee_rate?: number;
  base_taker_fee_rate?: number;
  base_rwa_maker_fee_rate?: number;
  base_rwa_taker_fee_rate?: number;
};

function stringField(value: unknown) {
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

function readStoredBrokerInfo(): BrokerInfoContextState {
  let profile: StoredBrokerProfile | null = null;
  if (typeof window !== "undefined") {
    try {
      const raw = walletGetItem("orderlyProfile");
      profile = raw ? (JSON.parse(raw) as StoredBrokerProfile) : null;
    } catch {
      profile = null;
    }
  }

  return {
    brokerId: profile?.brokerId,
    brokerName: profile?.brokerName || profile?.name || profile?.builderName,
    brokerTier: profile?.brokerTier,
    baseMakerFeeRate: profile?.baseMakerFeeRate,
    baseTakerFeeRate: profile?.baseTakerFeeRate,
    baseRwaMakerFeeRate: profile?.baseRwaMakerFeeRate,
    baseRwaTakerFeeRate: profile?.baseRwaTakerFeeRate,
    updateBrokerInfo: () => {},
    isLoading: false,
  };
}

function extractBrokerName(payload: BrokerNamePayload, brokerId: string) {
  const rows = payload.data?.rows || payload.rows || [];
  const row = rows.find(item => item.broker_id === brokerId) || rows[0];
  return stringField(row?.broker_name);
}

function extractBrokerTier(
  payload: BrokerTierPayload
): Partial<BrokerInfoContextState> {
  const data = payload.data || payload;
  return {
    brokerTier: stringField(data.type),
    baseMakerFeeRate: data.base_maker_fee_rate,
    baseTakerFeeRate: data.base_taker_fee_rate,
    baseRwaMakerFeeRate: data.base_rwa_maker_fee_rate,
    baseRwaTakerFeeRate: data.base_rwa_taker_fee_rate,
  };
}

function isAmbassadorProfile(
  profile?: StoredBrokerProfile | null,
  brokerId?: string
) {
  return (
    brokerId === "ambassador" ||
    profile?.role === "ambassador" ||
    profile?.brokerId === "ambassador"
  );
}

function extractDistributorName(payload: unknown) {
  const root =
    payload && typeof payload === "object" && !Array.isArray(payload)
      ? (payload as Record<string, unknown>)
      : {};
  const data =
    root.data && typeof root.data === "object" && !Array.isArray(root.data)
      ? (root.data as Record<string, unknown>)
      : root;
  return stringField(
    data.distributor_name ||
      data.distributorName ||
      root.distributor_name ||
      root.distributorName
  );
}

function persistBrokerInfo(accountId: string, info: BrokerInfoContextState) {
  if (typeof window === "undefined" || !info.brokerId) return;

  let existing: StoredBrokerProfile | null = null;
  try {
    const raw = walletGetItem("orderlyProfile");
    existing = raw ? (JSON.parse(raw) as StoredBrokerProfile) : null;
  } catch {
    existing = null;
  }

  const next = {
    ...existing,
    accountId,
    brokerId: info.brokerId,
    brokerName: info.brokerName || existing?.brokerName || info.brokerId,
    builderName: info.brokerName || existing?.builderName || info.brokerId,
    brokerTier: info.brokerTier,
    baseMakerFeeRate: info.baseMakerFeeRate,
    baseTakerFeeRate: info.baseTakerFeeRate,
    baseRwaMakerFeeRate: info.baseRwaMakerFeeRate,
    baseRwaTakerFeeRate: info.baseRwaTakerFeeRate,
    graduated: info.brokerId !== "demo",
    adminRegistered: info.brokerId !== "demo",
  };

  walletSetItem("current_user_broker_id", info.brokerId);
  const changed =
    existing?.brokerId !== next.brokerId ||
    existing?.brokerName !== next.brokerName ||
    existing?.builderName !== next.builderName ||
    existing?.brokerTier !== next.brokerTier ||
    existing?.baseMakerFeeRate !== next.baseMakerFeeRate ||
    existing?.baseTakerFeeRate !== next.baseTakerFeeRate ||
    existing?.baseRwaMakerFeeRate !== next.baseRwaMakerFeeRate ||
    existing?.baseRwaTakerFeeRate !== next.baseRwaTakerFeeRate;
  if (changed) {
    walletSetItem("orderlyProfile", JSON.stringify(next));
    window.dispatchEvent(new CustomEvent("authChanged"));
  }
}

export function useBrokerInfo() {
  return useContext(BrokerInfoContext) ?? readStoredBrokerInfo();
}

export function BrokerInfoProvider({
  children,
  accountId,
}: PropsWithChildren<{ accountId?: string }>) {
  const [info, setInfo] = useState<BrokerInfoContextState>(() =>
    readStoredBrokerInfo()
  );
  const [isLoading, setIsLoading] = useState(false);

  const updateBrokerInfo = useCallback(() => {
    const stored = readStoredAdminApiKey();
    const activeAccountId = accountId || stored?.accountId;
    if (!activeAccountId || !hasCompleteStoredAdminApiKey()) {
      setInfo(readStoredBrokerInfo());
      return;
    }

    setIsLoading(true);
    void (async () => {
      try {
        const storedInfo = readStoredBrokerInfo();
        let storedProfile: StoredBrokerProfile | null = null;
        if (typeof window !== "undefined") {
          try {
            const raw = walletGetItem("orderlyProfile");
            storedProfile = raw
              ? (JSON.parse(raw) as StoredBrokerProfile)
              : null;
          } catch {
            storedProfile = null;
          }
        }

        if (isAmbassadorProfile(storedProfile, storedInfo.brokerId)) {
          const summary = await signedAdminRequest({
            endpoint: "/v1/vanguard/summary",
            method: "GET",
          }).catch(() => null);
          const brokerName =
            extractDistributorName(summary) ||
            storedInfo.brokerName ||
            storedProfile?.builderName ||
            "Ambassador distributor";
          const nextInfo: BrokerInfoContextState = {
            ...storedInfo,
            brokerId: "ambassador",
            brokerName,
            updateBrokerInfo,
            isLoading: false,
          };
          persistBrokerInfo(activeAccountId, nextInfo);
          setInfo(nextInfo);
          return;
        }

        const accountInfo = await fetchAdminAccountInfo({
          accountId: activeAccountId,
        });
        const brokerId =
          stringField(accountInfo?.broker_id) || storedInfo.brokerId;
        if (!brokerId) {
          setInfo(storedInfo);
          return;
        }

        if (isAmbassadorProfile(storedProfile, brokerId)) {
          const summary = await signedAdminRequest({
            endpoint: "/v1/vanguard/summary",
            method: "GET",
          }).catch(() => null);
          const brokerName =
            extractDistributorName(summary) ||
            storedInfo.brokerName ||
            storedProfile?.builderName ||
            "Ambassador distributor";
          const nextInfo: BrokerInfoContextState = {
            ...storedInfo,
            brokerId: "ambassador",
            brokerName,
            updateBrokerInfo,
            isLoading: false,
          };
          persistBrokerInfo(activeAccountId, nextInfo);
          setInfo(nextInfo);
          return;
        }

        const [brokerNameResult, brokerTierResult] = await Promise.allSettled([
          signedAdminRequest<BrokerNamePayload>({
            endpoint: `/v1/public/broker/name?broker_id=${encodeURIComponent(brokerId)}`,
            method: "GET",
          }),
          signedAdminRequest<BrokerTierPayload>({
            endpoint: "/v1/broker/broker_info",
            method: "GET",
          }),
        ]);
        const brokerName =
          brokerNameResult.status === "fulfilled"
            ? extractBrokerName(brokerNameResult.value, brokerId)
            : undefined;
        const brokerTier =
          brokerTierResult.status === "fulfilled"
            ? extractBrokerTier(brokerTierResult.value)
            : {};
        const nextInfo: BrokerInfoContextState = {
          ...storedInfo,
          ...brokerTier,
          brokerId,
          brokerName: brokerName || storedInfo.brokerName || brokerId,
          updateBrokerInfo,
          isLoading: false,
        };
        persistBrokerInfo(activeAccountId, nextInfo);
        setInfo(nextInfo);
      } catch {
        setInfo(readStoredBrokerInfo());
      } finally {
        setIsLoading(false);
      }
    })();
  }, [accountId]);

  useEffect(() => {
    updateBrokerInfo();
  }, [updateBrokerInfo]);

  const value = useMemo(
    () => ({
      ...info,
      updateBrokerInfo,
      isLoading,
    }),
    [info, isLoading, updateBrokerInfo]
  );

  return (
    <BrokerInfoContext.Provider value={value}>
      {children}
    </BrokerInfoContext.Provider>
  );
}
